  1	import * as React from 'react';
  2	import {
  3	  GetPublicAccessBlockCommandOutput,
  4	  GetBucketPolicyStatusCommandOutput,
  5	} from '@aws-sdk/client-s3';
  6	import { S3Context } from '@odf/core/components/s3-browser/s3-context';
  7	import { CheckboxTree } from '@odf/shared/checkbox-tree';
  8	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  9	import { StatusBox, LoadingBox } from '@odf/shared/generic/status-box';
 10	import { S3Commands } from '@odf/shared/s3';
 11	import { isNoPabError } from '@odf/shared/s3/utils';
 12	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 13	import {
 14	  ListPageBody,
 15	  ListPageHeader,
 16	  useModal,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import * as _ from 'lodash-es';
 19	import { useParams } from 'react-router-dom-v5-compat';
 20	import useSWRMutation from 'swr/mutation';
 21	import {
 22	  Button,
 23	  ButtonVariant,
 24	  Alert,
 25	  AlertVariant,
 26	} from '@patternfly/react-core';
 27	import {
 28	  BUCKET_POLICY_STATUS_CACHE_KEY_SUFFIX,
 29	  BUCKET_PUBLIC_ACCESS_BLOCK_CACHE_KEY_SUFFIX,
 30	} from '../../../constants';
 31	import PublicAccessBlockConfirmation from '../../../modals/s3-browser/public-access-block-confirmation/PublicAccessBlockConfirmation';
 32	import {
 33	  SupportedConfig,
 34	  getOptions,
 35	  areAllChildrenChecked,
 36	  isNoChildChecked,
 37	  showModal,
 38	} from './utils';
 39	
 40	type PabOutput = GetPublicAccessBlockCommandOutput;
 41	
 42	type PublicAccessBlockProps = {
 43	  obj: { fresh?: boolean; triggerRefresh: () => void };
 44	};
 45	
 46	type PabAlertProps = {
 47	  checkedItems: Set<string>;
 48	  policyStatusData: GetBucketPolicyStatusCommandOutput;
 49	};
 50	
 51	type PabBodyProps = {
 52	  checkedItems: Set<string>;
 53	  setCheckedItems: React.Dispatch<React.SetStateAction<Set<string>>>;
 54	  manage: boolean;
 55	};
 56	
 57	type PabFooterProps = {
 58	  checkedItems: Set<string>;
 59	  triggerRefresh: () => void;
 60	  bucketName: string;
 61	  s3Client: S3Commands;
 62	  pabData: PabOutput;
 63	};
 64	
 65	const PabAlert: React.FC<PabAlertProps> = ({
 66	  checkedItems,
 67	  policyStatusData,
 68	}) => {
 69	  const { t } = useCustomTranslation();
 70	
 71	  const isPublicPolicy: boolean =
 72	    (policyStatusData ?? {})?.PolicyStatus?.IsPublic || false;
 73	  const allChecked = areAllChildrenChecked(checkedItems);
 74	  const noChecked = isNoChildChecked(checkedItems);
 75	
 76	  if (isPublicPolicy && noChecked) {
 77	    return (
 78	      <Alert
 79	        variant={AlertVariant.danger}
 80	        title={t('Your bucket is currently publicly accessible.')}
 81	        className="pf-v6-u-mb-sm"
 82	      >
 83	        <p>
 84	          {t(
 85	            'The current bucket policy and object permissions allow public access. This may unintentionally expose your data to users outside your organization and increase the risk of data leaks or unauthorized actions.'
 86	          )}
 87	        </p>
 88	      </Alert>
 89	    );
 90	  }
 91	
 92	  if (!allChecked) {
 93	    return (
 94	      <Alert
 95	        variant={AlertVariant.warning}
 96	        title={t(
 97	          'One or more settings might have allowed public access to your bucket'
 98	        )}
 99	        className="pf-v6-u-mb-sm"
100	      />
101	    );
102	  }
103	
104	  return null;
105	};
106	
107	const PabBody: React.FC<PabBodyProps> = ({
108	  checkedItems,
109	  setCheckedItems,
110	  manage,
111	}) => {
112	  const { t } = useCustomTranslation();
113	
114	  return (
115	    <CheckboxTree
116	      checkedItems={checkedItems}
117	      setCheckedItems={setCheckedItems}
118	      options={getOptions(manage, checkedItems, t)}
119	      treeViewProps={{ hasGuides: true }}
120	    />
121	  );
122	};
123	
124	const PabFooter: React.FC<PabFooterProps> = ({
125	  checkedItems,
126	  triggerRefresh,
127	  bucketName,
128	  s3Client,
129	  pabData,
130	}) => {
131	  const { t } = useCustomTranslation();
132	
133	  const launcher = useModal();
134	
135	  const [inProgress, setInProgress] = React.useState<boolean>(false);
136	  const [error, setError] = React.useState<Error>();
137	
138	  const handleSubmit = (event) => {
139	    event.preventDefault();
140	    setInProgress(true);
141	
142	    const publicAccessBlockConfiguration = {};
143	    Object.entries(SupportedConfig).forEach(([key, value]) => {
144	      publicAccessBlockConfiguration[key] = checkedItems.has(value);
145	    });
146	
147	    s3Client
148	      .putPublicAccessBlock({
149	        Bucket: bucketName,
150	        PublicAccessBlockConfiguration: publicAccessBlockConfiguration,
151	      })
152	      .then(() => {
153	        triggerRefresh();
154	        setInProgress(false);
155	      })
156	      .catch((err) => {
157	        setError(err);
158	        setInProgress(false);
159	      });
160	  };
161	
162	  // show this modal only when disabling a configuration that is currently enabled. Otherwise, do not show it
163	  const [shouldShowModal, configText] = showModal(pabData, checkedItems, t);
164	  const launchConfirmationModal = () =>
165	    launcher(PublicAccessBlockConfirmation, {
166	      extraProps: { onDisable: handleSubmit, configText },
167	      isOpen: true,
168	    });
169	
170	  return (
171	    <ButtonBar
172	      inProgress={inProgress}
173	      errorMessage={error?.message || JSON.stringify(error)}
174	      className="pf-v6-u-mt-xl"
175	    >
176	      <span className="pf-v6-u-mt-sm">
177	        <Button
178	          variant={ButtonVariant.primary}
179	          onClick={shouldShowModal ? launchConfirmationModal : handleSubmit}
180	          className="pf-v6-u-mr-xs"
181	          isDisabled={!!error || inProgress}
182	        >
183	          {t('Save changes')}
184	        </Button>
185	        <Button
186	          variant={ButtonVariant.secondary}
187	          onClick={triggerRefresh}
188	          className="pf-v6-u-ml-xs"
189	        >
190	          {t('Cancel')}
191	        </Button>
192	      </span>
193	    </ButtonBar>
194	  );
195	};
196	
197	const PublicAccessBlockContent: React.FC<PublicAccessBlockProps['obj']> = ({
198	  triggerRefresh,
199	}) => {
200	  const { t } = useCustomTranslation();
201	  const [manage, setManage] = React.useState(false);
202	  const [checkedItems, setCheckedItems] = React.useState(new Set<string>());
203	  const setItemsRef = React.useRef(true);
204	
205	  const { bucketName } = useParams();
206	  const { s3Client } = React.useContext(S3Context);
207	
208	  const { data: policyStatus, trigger: triggerPolicyStatus } = useSWRMutation(
209	    `${s3Client.providerType}-${bucketName}-${BUCKET_POLICY_STATUS_CACHE_KEY_SUFFIX}`,
210	    () => s3Client.getBucketPolicyStatus({ Bucket: bucketName })
211	  );
212	  const {
213	    data: pabData = {} as PabOutput,
214	    isMutating: isLoading,
215	    error,
216	    trigger: triggerPab,
217	  } = useSWRMutation(
218	    `${s3Client.providerType}-${bucketName}-${BUCKET_PUBLIC_ACCESS_BLOCK_CACHE_KEY_SUFFIX}`,
219	    () => s3Client.getPublicAccessBlock({ Bucket: bucketName })
220	  );
221	
222	  const noPabError = isNoPabError(error);
223	
224	  // initial fetch on first mount or remounts only
225	  React.useEffect(() => {
226	    triggerPolicyStatus().catch((err) => {
227	      // eslint-disable-next-line no-console
228	      console.error(err);
229	    });
230	    triggerPab().catch((err) => {
231	      // eslint-disable-next-line no-console
232	      console.error(err);
233	    });
234	    // eslint-disable-next-line react-hooks/exhaustive-deps
235	  }, []);
236	
237	  React.useEffect(() => {
238	    if (!_.isEmpty(pabData) && setItemsRef.current) {
239	      setItemsRef.current = false;
240	      const checked = new Set<string>();
241	      Object.entries(SupportedConfig).forEach(([key, value]) => {
242	        if (pabData?.PublicAccessBlockConfiguration?.[key] === true)
243	          checked.add(value);
244	      });
245	      setCheckedItems(checked);
246	    }
247	  }, [pabData, setCheckedItems]);
248	
249	  if (isLoading || (error && !noPabError)) {
250	    return <StatusBox loaded={!isLoading} loadError={isLoading ? '' : error} />;
251	  }
252	
253	  return (
254	    <>
255	      <ListPageHeader
256	        title={t('Block public access')}
257	        helpText={t(
258	          'To ensure that public access to your S3 bucket and its objects is blocked, turn on Block all public access.'
259	        )}
260	      >
261	        {!manage && (
262	          <Button
263	            variant={ButtonVariant.primary}
264	            onClick={() => setManage(true)}
265	          >
266	            {t('Manage public access settings')}
267	          </Button>
268	        )}
269	      </ListPageHeader>
270	      <ListPageBody>
271	        {!manage && (
272	          <PabAlert
273	            checkedItems={checkedItems}
274	            policyStatusData={policyStatus}
275	          />
276	        )}
277	        <PabBody
278	          checkedItems={checkedItems}
279	          setCheckedItems={setCheckedItems}
280	          manage={manage}
281	        />
282	        {manage && (
283	          <PabFooter
284	            checkedItems={checkedItems}
285	            triggerRefresh={triggerRefresh}
286	            bucketName={bucketName}
287	            s3Client={s3Client}
288	            pabData={pabData}
289	          />
290	        )}
291	      </ListPageBody>
292	    </>
293	  );
294	};
295	
296	export const PublicAccessBlock: React.FC<PublicAccessBlockProps> = ({
297	  obj: { fresh, triggerRefresh },
298	}) =>
299	  fresh ? (
300	    <PublicAccessBlockContent triggerRefresh={triggerRefresh} />
301	  ) : (
302	    <LoadingBox />
303	  );

